// 🤖 Generated by: skill-vitest-unit-tests | product.ts | 2026-06-25T18:27:04
import { describe, it, expect, beforeEach, vi } from 'vitest';
import request from 'supertest';
import express from 'express';

// ── Mock repository module before importing the router ────────────────────────
vi.mock('../../src/repositories/productsRepo');

import productRouter from '../../src/routes/product';
import { getProductsRepository } from '../../src/repositories/productsRepo';

// ── Typed mock handle ─────────────────────────────────────────────────────────
const mockProductsRepo = {
  findAll: vi.fn(),
  findById: vi.fn(),
  findByName: vi.fn(),
  create: vi.fn(),
  update: vi.fn(),
  delete: vi.fn(),
};

// ── Test fixtures ─────────────────────────────────────────────────────────────
const makeProduct = (overrides: Partial<{
  productId: number;
  supplierId: number;
  name: string;
  description: string;
  price: number;
  sku: string;
  unit: string;
  imgName: string;
  stockLevel: number;
}> = {}) => ({
  productId: 1,
  supplierId: 1,
  name: 'Test Widget',
  description: 'A test widget',
  price: 50.00,
  sku: 'SKU-001',
  unit: 'each',
  imgName: 'widget.png',
  stockLevel: 100,
  ...overrides,
});

let app: express.Express;

beforeEach(() => {
  vi.clearAllMocks();
  vi.mocked(getProductsRepository).mockResolvedValue(mockProductsRepo as any);

  app = express();
  app.use(express.json());
  app.use('/products', productRouter);
});

// ─── GET /products/search/price-range ────────────────────────────────────────
describe('GET /products/search/price-range', () => {
  it('returns 200 with products whose price falls within the range', async () => {
    const products = [
      makeProduct({ productId: 1, name: 'Cheap Widget', price: 10.00 }),
      makeProduct({ productId: 2, name: 'Mid Widget',   price: 50.00 }),
      makeProduct({ productId: 3, name: 'Pricey Widget', price: 200.00 }),
    ];
    mockProductsRepo.findAll.mockResolvedValue(products);

    const res = await request(app).get('/products/search/price-range?min=20&max=100');

    expect(res.status).toBe(200);
    expect(res.body).toHaveLength(1);
    expect(res.body[0]).toMatchObject({ productId: 2, name: 'Mid Widget', price: 50.00 });
  });

  it('returns 200 with empty array when no products match the range', async () => {
    const products = [
      makeProduct({ productId: 1, price: 5.00 }),
      makeProduct({ productId: 2, price: 500.00 }),
    ];
    mockProductsRepo.findAll.mockResolvedValue(products);

    const res = await request(app).get('/products/search/price-range?min=100&max=200');

    expect(res.status).toBe(200);
    expect(res.body).toEqual([]);
  });

  it('returns 200 with products at exact boundary prices (min === max)', async () => {
    const products = [
      makeProduct({ productId: 1, name: 'Exact Price Widget', price: 75.00 }),
      makeProduct({ productId: 2, name: 'Other Widget',       price: 80.00 }),
    ];
    mockProductsRepo.findAll.mockResolvedValue(products);

    const res = await request(app).get('/products/search/price-range?min=75&max=75');

    expect(res.status).toBe(200);
    expect(res.body).toHaveLength(1);
    expect(res.body[0]).toMatchObject({ productId: 1, price: 75.00 });
  });

  it('returns 400 when min param is missing', async () => {
    const res = await request(app).get('/products/search/price-range?max=100');

    expect(res.status).toBe(400);
    expect(res.body).toHaveProperty('error');
    expect(mockProductsRepo.findAll).not.toHaveBeenCalled();
  });

  it('returns 400 when max param is missing', async () => {
    const res = await request(app).get('/products/search/price-range?min=10');

    expect(res.status).toBe(400);
    expect(res.body).toHaveProperty('error');
    expect(mockProductsRepo.findAll).not.toHaveBeenCalled();
  });

  it('returns 400 when both min and max params are missing', async () => {
    const res = await request(app).get('/products/search/price-range');

    expect(res.status).toBe(400);
    expect(res.body).toHaveProperty('error');
    expect(mockProductsRepo.findAll).not.toHaveBeenCalled();
  });

  it('returns 400 when min is non-numeric', async () => {
    const res = await request(app).get('/products/search/price-range?min=abc&max=100');

    expect(res.status).toBe(400);
    expect(res.body).toHaveProperty('error');
    expect(mockProductsRepo.findAll).not.toHaveBeenCalled();
  });

  it('returns 400 when max is non-numeric', async () => {
    const res = await request(app).get('/products/search/price-range?min=10&max=abc');

    expect(res.status).toBe(400);
    expect(res.body).toHaveProperty('error');
    expect(mockProductsRepo.findAll).not.toHaveBeenCalled();
  });

  it('returns 422 when min is greater than max', async () => {
    const res = await request(app).get('/products/search/price-range?min=200&max=50');

    expect(res.status).toBe(422);
    expect(res.body).toHaveProperty('error');
    expect(mockProductsRepo.findAll).not.toHaveBeenCalled();
  });
});
